//   4. Work delegate now accepts CancellationToken so it can cooperate

using System;
using System.Threading;
using System.Threading.Tasks;

public class TimedExecutor
{
    /// <summary>
    /// Executes work with a timeout using cooperative cancellation.
    /// The work function MUST check the CancellationToken at regular intervals
    /// for cancellation to be responsive.
    /// </summary>
    public T ExecuteWithTimeout<T>(Func<CancellationToken, T> work, TimeSpan timeout)
    {
        using var cts = new CancellationTokenSource(timeout);

        try
        {
            Task<T> task = Task.Run(() => work(cts.Token), cts.Token);
            return task.GetAwaiter().GetResult();
        }
        catch (OperationCanceledException) when (cts.IsCancellationRequested)
        {
            throw new TimeoutException($"Operation exceeded {timeout.TotalSeconds}s timeout");
        }
    }

    // Overload that also accepts an external cancellation token
    // (e.g., from HttpContext.RequestAborted or a parent scope)
    public T ExecuteWithTimeout<T>(
        Func<CancellationToken, T> work,
        TimeSpan timeout,
        CancellationToken externalToken)
    {
        using var cts = CancellationTokenSource.CreateLinkedTokenSource(externalToken);
        cts.CancelAfter(timeout);

        try
        {
            Task<T> task = Task.Run(() => work(cts.Token), cts.Token);
            return task.GetAwaiter().GetResult();
        }
        catch (OperationCanceledException) when (!externalToken.IsCancellationRequested)
        {
            throw new TimeoutException($"Operation exceeded {timeout.TotalSeconds}s timeout");
        }
        // If externalToken was cancelled, OperationCanceledException propagates as-is
    }
}
